def set_theme():
    if globalvars.steamui_ver >= 1218:
        background_color = "#383635"
        segment_color = "#4d6d8c"
        window_color = "#383635"
        text_color = "#e5e4dc"
    else:
        background_color = "#3e4637"
        segment_color = "#bdbd52"
        window_color = "#4e5843"
        text_color = "#bdbd52"
    return background_color, segment_color, window_color, text_color

class SegmentedProgressbar:
    def __init__(self, master, width=300, height=30, segments=10, gap=2, background_color="#3e4637", segment_color="#bdbd52", segment_height=None, segment_width=None):
        background_color, segment_color, window_color, text_color = set_theme()
        self.canvas = tk.Canvas(master, width=width, height=height, bd=1, highlightthickness=0)
        self.width = width
        self.height = height
        self.segments = segments
        self.gap = gap
        self.segment_width = segment_width if segment_width else (width - (segments - 1) * gap) / segments
        self.background_color = background_color
        self.segment_color = segment_color
        self.segment_height = segment_height if segment_height else height
        self.background_id = None
        self.segment_ids = []
        self.canvas.pack(padx=0, pady=0)
        self.draw_background()

    def draw_background(self):
        if not self.background_id:
            self.background_id = self.canvas.create_rectangle(0, 0, self.width, self.height, fill=self.background_color, outline="")

    def update_progress(self, progress):
        filled_segments = int(progress * self.segments / 100)

        for i in range(self.segments):
            x1 = i * (self.segment_width + self.gap) + 7
            x2 = x1 + self.segment_width
            y1 = ((self.height - self.segment_height) / 2) + 1
            y2 = y1 + self.segment_height
            color = self.segment_color if i < filled_segments else self.background_color

            if len(self.segment_ids) <= i:
                segment_id = self.canvas.create_rectangle(x1, y1, x2, y2, fill=color, outline="")
                self.segment_ids.append(segment_id)
            else:
                self.canvas.itemconfig(self.segment_ids[i], fill=color)

def create_tkinter_window(apps_to_neuter):
    global window
    background_color, segment_color, window_color, text_color = set_theme()
    window = tk.Tk()
    window.title("Neutering...")
    window.geometry("820x400")
    window.resizable(False, False)
    window.configure(bg=window_color)
    icon_path = os.path.join(sys._MEIPASS, "files", "icons", "t1.ico") if getattr(sys, 'frozen', False) else os.path.join(".", "files", "icons", "t1.ico")
    set_window_icon(window, icon_path)

    thread_icon = Thread(target=update_icon, args=(window,))
    thread_icon.daemon = True
    thread_icon.start()

    frame = tk.Frame(window, bg=window_color)
    frame.pack(fill='both', expand=True)
    canvas = tk.Canvas(frame, bg=window_color, bd=0, highlightthickness=0)
    canvas.pack(side='left', fill='both', expand=True)
    scrollbar = tk.Scrollbar(frame, orient='vertical', command=canvas.yview)
    scrollbar.pack(side='right', fill='y')
    canvas.configure(yscrollcommand=scrollbar.set)
    canvas_frame = tk.Frame(canvas, bg=window_color, bd=0, highlightthickness=0) 
    canvas.create_window((0, 0), window=canvas_frame, anchor='nw')

    # Enable mouse wheel scrolling
    def on_mousewheel(event):
        canvas.yview_scroll(int(-1 * (event.delta / 120)), "units")

    canvas.bind_all("<MouseWheel>", on_mousewheel)

    def update_canvas_scroll_region():
        canvas.update_idletasks()
        canvas.config(scrollregion=canvas.bbox('all'))
        canvas.yview_moveto(1)

    def immediate_stop():
        halt_processing.set()
        bottom_label.config(text="Cancelling...")

    bottom_label = tk.Label(window, text="This banner should change. Ffs Python.", anchor="center")
    bottom_label.pack(side="bottom", fill="x", pady=0)
    window.protocol("WM_DELETE_WINDOW", immediate_stop)

    progress_bars = []
    task_count = len(apps_to_neuter)

    def create_next_progress_bar(task_id):
        if task_id <= task_count:
            background_color, segment_color, window_color, text_color = set_theme()
            progress_frame = tk.Frame(canvas_frame, bg=window_color)
            progress_frame.pack(pady=3, anchor="w")

            progress_canvas = SegmentedProgressbar(progress_frame, width=212, height=20, segments=17, gap=5, background_color=background_color, segment_color=segment_color, segment_height=14, segment_width=7)
            progress_canvas.canvas.pack(padx=10, pady=3, side='left')

            label = tk.Label(progress_frame, text="Calculating...", bg=window_color, fg=text_color, font=("Courier New", 9))
            label.pack(side='left', padx=10)

            progress_bars.append(progress_canvas)

            update_canvas_scroll_region()

            thread = Thread(target=download_app, args=(progress_canvas, label, task_id, lambda: create_next_progress_bar(task_id + 1), task_count, apps_to_neuter[task_id]))
            thread.start()

    create_next_progress_bar(1)
    
    def update_bottom_label():
        if not halt_processing.is_set():
            new_text = sentences[random.randint(0, len(sentences) - 1)]
            bottom_label.config(text=new_text)
            bottom_label.after(5000, update_bottom_label)

    update_bottom_label()

    window.mainloop()

