def neuter_steamworks_SDK(islan):
    """ Neuters the steamworks SDK, specifically only the content tool at the moment"""
    # Determine the octal IP and create the replacement string.
    server_ip = config["server_ip"]
    public_ip = config["public_ip"]
    if islan:
        octal_ip_str = server_ip
    else:
        octal_ip_str = public_ip

    # bytes form for binary search/replace, string form for neuter_file/cfg
    octal_ip = octal_ip_str.encode('latin-1')

    neuter_string = [
        (b"ftp.valvesoftware.com", octal_ip, b"SteamWorks SDK Content Tool FTP Address")
    ]

    steamworks_data_root = os.path.join("files", "steamworks_data", "sdk")

    # This will hold all neutered outputs keyed by *relative* path from steamworks_data_root
    neutered_files = {}

    # ------------------------------------------------------------------
    # Neuter ContentTool.exe -> store neutered bytes in memory
    # ------------------------------------------------------------------
    content_tool_path = os.path.join(steamworks_data_root, "tools", "ContentTool.exe")
    backup_path = os.path.join(steamworks_data_root, "tools", "ContentTool.exe.bak")

    if os.path.exists(content_tool_path):
        with open(content_tool_path, 'rb') as f:
            file_data = f.read()

        modified_data = config_replace_in_file(
            file_data,
            content_tool_path,
            neuter_string,
            1
        )

        rel_ct_path = os.path.relpath(content_tool_path, steamworks_data_root)
        neutered_files[rel_ct_path] = modified_data

        log.info(f"Neutered {content_tool_path} (memory only, will be injected into zip).")
    else:
        log.warning("ContentTool.exe not found at %s; nothing to neuter.", content_tool_path)

    # ------------------------------------------------------------------
    # Neuter the other redistributable / client binaries with neuter_file
    # ------------------------------------------------------------------
    redistrib_files = [
        # Windows
        os.path.join(steamworks_data_root, "redistributable_bin", "Steam.dll"),

        os.path.join(steamworks_data_root, "redistributable_bin", "steamclient.dll"),

        # Linux
        os.path.join(steamworks_data_root, "redistributable_bin", "linux32", "libsteam.so"),
        os.path.join(steamworks_data_root, "redistributable_bin", "linux32", "libSteam.so"),
        os.path.join(steamworks_data_root, "redistributable_bin", "linux32", "steamclient.so"),

        # macOS
        os.path.join(steamworks_data_root, "redistributable_bin", "osx32", "libsteam.dylib"),
        os.path.join(steamworks_data_root, "redistributable_bin", "osx32", "steamclient.dylib"),

        # client exe
        os.path.join(steamworks_data_root, "client", "steam.exe"),
    ]

    for path in redistrib_files:
        if not os.path.exists(path):
            continue

        try:
            with open(path, "rb") as f:
                original_bytes = f.read()

            # neuter_file returns raw bytes
            neutered_bytes = neuter_file(
                original_bytes,
                octal_ip_str,
                config["dir_server_port"],
                os.path.basename(path),
                islan
            )

            # FileSignatureModifier ALSO expects raw bytes
            modifier = FileSignatureModifier(neutered_bytes)
            final_bytes = modifier.modify_file()

            rel_path = os.path.relpath(path, steamworks_data_root)
            neutered_files[rel_path] = final_bytes

            log.info("Neutered %s (will be injected into zip).", path)

        except Exception as e:
            log.warning("Failed to neuter %s: %s", path, e)

    # ------------------------------------------------------------------
    # Update steam.cfg content server IP -> neutered copy only in zip
    # ------------------------------------------------------------------
    cfg_path = os.path.join(steamworks_data_root, "client", "steam.cfg")
    if os.path.exists(cfg_path):
        try:
            with open(cfg_path, 'r', encoding='latin-1') as f:
                cfg_text = f.read()

            new_text, count = re.subn(
                r'(SdkContentServerAdrs\s*=\s*")([^"]*)(")',
                lambda m: f'{m.group(1)}{octal_ip_str}{m.group(3)}',
                cfg_text
            )

            rel_cfg = os.path.relpath(cfg_path, steamworks_data_root)

            if count:
                neutered_files[rel_cfg] = new_text.encode('latin-1')
                log.info("Updated SdkContentServerAdrs in %s (will be injected into zip) to %s",
                         cfg_path, octal_ip_str)
            else:
                log.warning("No SdkContentServerAdrs line found in %s; leaving original in zip.",
                            cfg_path)
        except Exception as e:
            log.warning("Failed to update steam.cfg: %s", e)
    else:
        log.warning("steam.cfg not found at %s", cfg_path)

    # ------------------------------------------------------------------
    # Build zip from steamworks_data_root, overriding neutered paths
    # ------------------------------------------------------------------
    zip_filename = os.path.join("client", f"steamworks_sdk_{'lan' if islan else 'wan'}.zip")
    with zipfile.ZipFile(zip_filename, 'w', zipfile.ZIP_DEFLATED) as zipf:
        for root, dirs, files in os.walk(steamworks_data_root):
            for file in files:
                file_path = os.path.join(root, file)
                rel = os.path.relpath(file_path, steamworks_data_root)

                # If we have a neutered version, use that instead of disk contents
                if rel in neutered_files:
                    zipf.writestr(rel, neutered_files[rel])
                else:
                    zipf.write(file_path, rel)

    log.info(f"SteamWorks SDK has been neutered and saved as {zip_filename}.")

def grab_correct_steamworks_sdk():
    """Ensure the proper Steamworks SDK version is extracted into files/steamworks_data
       based on globalvars.CDDB_datetime.
    """

    # Map SDK releases by date -> zip suffix (steamworks_sdk_<suffix>.zip)
    SDK_RELEASES = [
        (date(2008, 5, 1),  "100"),   # 1.00
        (date(2008, 8, 4),  "101"),   # 1.01
        (date(2008, 9, 4),  "102"),   # 1.02
        (date(2009, 1, 16), "103"),   # 1.03
        (date(2009, 5, 6),  "104"),   # 1.04
        (date(2009, 6, 11), "105"),   # 1.05
        (date(2009, 9, 30), "106"),   # 1.06
        (date(2009,12,16),  "107"),   # 1.07
        (date(2010, 1,27),  "108"),   # 1.08
        (date(2010, 5,12),  "109"),   # 1.09
        (date(2010, 7,20),  "110"),   # 1.10
        (date(2010, 8,26),  "111"),   # 1.11
        (date(2010,11,10),  "112"),   # 1.12
        (date(2011, 4,26),  "113"),   # 1.13
        (date(2011, 5,16),  "114"),   # 1.14
        (date(2011, 6, 1),  "115"),   # 1.15
        (date(2011, 7,29),  "116"),   # 1.16
        (date(2011,11, 2),  "117"),   # 1.17
        (date(2012, 2, 7),  "118"),   # 1.18
        (date(2012, 3,22),  "119"),   # 1.19
        (date(2012, 8,30),  "120"),   # 1.20
        (date(2012,12,21),  "123"),   # 1.23
        (date(2013, 2,25),  "123a"),  # 1.23a
        #(date(2013, 7,17),  "124"),   # 1.24
        #(date(2013,10, 7),  "125a"),  # 1.25a
        #(date(2013,11, 7),  "126"),   # 1.26
        #(date(2013,11,14),  "126a"),  # 1.26a
        #(date(2013,12,17),  "127"),   # 1.27
        #(date(2014, 1,28),  "128"),   # 1.28
        #(date(2014, 4,24),  "129"),   # 1.29
        #(date(2014, 5,27),  "129a"),  # 1.29a
    ]

    # Parse blob datetime
    blob_dt = datetime.strptime(globalvars.CDDB_datetime, "%m/%d/%Y %H:%M:%S")
    blob_date = blob_dt.date()

    # Choose latest SDK with release_date <= blob_date
    sdk_suffix = None
    for rel_date, suffix in SDK_RELEASES:
        if rel_date <= blob_date:
            sdk_suffix = suffix
        else:
            break

    if sdk_suffix is None:
        sdk_suffix = SDK_RELEASES[0][1]
        log.warning(
            "Blob date %s precedes first known SDK; using oldest SDK %s",
            blob_date, sdk_suffix
        )

    log.info("Selected Steamworks SDK version suffix %s for blob date %s",
             sdk_suffix, blob_date)

    steamworks_data_root = os.path.join("files", "steamworks_data")
    archives_root = os.path.join("files", "steamworks_archives")
    archive_path = os.path.join(archives_root, f"steamworks_sdk_{sdk_suffix}.zip")

    # Marker file we expect for the required version
    correct_marker = os.path.join(steamworks_data_root, f"{sdk_suffix}.txt")

    # Does the correct marker exist?
    if os.path.exists(correct_marker):
        log.info("Steamworks SDK %s already present; no extraction needed.", sdk_suffix)
        return False

    # Marker missing or wrong version ? re-extract
    log.info("Extracting Steamworks SDK %s...", sdk_suffix)

    # Ensure root exists, then clear its contents without deleting the folder itself
    if not os.path.isdir(steamworks_data_root):
        os.makedirs(steamworks_data_root, exist_ok=True)
    else:
        # delete everything inside steamworks_data_root
        for entry in os.listdir(steamworks_data_root):
            entry_path = os.path.join(steamworks_data_root, entry)
            try:
                if os.path.isfile(entry_path) or os.path.islink(entry_path):
                    os.remove(entry_path)
                else:
                    shutil.rmtree(entry_path, ignore_errors=True)
            except Exception as e:
                log.warning("Failed to remove %s while clearing SDK dir: %s",
                            entry_path, e)

    # Extract archive if present
    if not os.path.exists(archive_path):
        log.info(f"Steamworks SDK archive not found: {archive_path}. Cannot extract!")
        return False

    with zipfile.ZipFile(archive_path, 'r') as zf:
        zf.extractall(steamworks_data_root)

    # Write the correct marker
    with open(correct_marker, "w", encoding="utf-8") as f:
        f.write(f"Current Steamworks SDK version: {sdk_suffix}\n")

    log.info("Steamworks SDK %s extracted and marker %s created.", sdk_suffix, correct_marker)
    return True


