def log_blob_information(silent=False):
    date_obj = datetime.strptime(globalvars.CDDB_datetime, "%m/%d/%Y %H:%M:%S")
    formatted_date = date_obj.strftime("%Y/%m/%d") # Changed date to Y/M/D to avoid confusion
    globalvars.formatted_date = formatted_date
    globalvars.formatted_underscore_date = date_obj.strftime("%Y-%m-%d") # For neutering
    # TODO NEED TO DEPRECATE THIS IN FAVOR OF PROTOCOL VERSIONING
    if formatted_date < "2003/09/11":
        globalvars.tgt_version = "1"
    elif globalvars.steamui_ver < 61:  # guessing steamui version when steam client interface v2 changed to v3
        globalvars.tgt_version = "1"
    else:
        globalvars.tgt_version = "2"  # config file states 2 as default
    if not silent:
        print()
        log.info("Steam Environment Information:")
        log.info(f"  Steam Version   : {globalvars.steam_ver}")
        if formatted_date < "2003/09/11":
            log.info(f"  Game Version    : {globalvars.steamui_ver}")
        else:
            log.info(f"  SteamUI Version : {globalvars.steamui_ver}")
        log.info(f"  Blob Timestamp  : {formatted_date}")
        print()

def auto_neuter(param1, param2, param3):
    stop_event.clear()
    halt_processing.clear()
    app_id = None
    app_ver = None

    #create folders
    for directory in [config["storagedir"], config["manifestdir"]]:
        try:
            os.mkdir(directory)
            # log.info(f"Created directory: {directory}")
        except:
            pass

    main_key_path = os.path.join("files", "configs", "main_key_1024.der")
    network_key_path = os.path.join("files", "configs", "network_key_512.der")

    # Check if both files exist
    if not os.path.exists(main_key_path) and not os.path.exists(network_key_path):
        log.warning("Main and network keys not found. Generating new keys.")
        encryption.generate_and_export_rsa_keys()
    else:
        log.debug("Main and network keys already exist.")

    encryption.main_key, encryption.network_key = encryption.import_rsa_keys()
    log.debug("RSA keys imported successfully.")
    encryption.BERstring = encryption.network_key.public_key().export_key("DER")
    encryption.signed_mainkey_reply = encryption.get_mainkey_reply()
    log.info("RSA keys setup completed.")

    try:
        if config['csds_ipport'] == "":
            contentserver = (bytes(config["server_ip"], "UTF-8"), int(config["contentdir_server_port"]))
            log.info(f"Using content server {config['server_ip']}:{config['contentdir_server_port']}.")
        else:
            # Example value of config['csds_ipport']
            csds_ipport = config['csds_ipport']  # Assuming this is '192.168.3.180:27037'

            # Split the string into IP and port
            ip, port = csds_ipport.split(':')

            # Convert the port to an integer
            port = int(port)
            contentserver = (ip, port)
            log.info(f"Using content server {ip}:{port}.")
    except Exception as e:
        log.warning(f"Error reading content server config: {e}. Using default localhost server.")
        contentserver = (b"127.0.0.1", 27037)


    lan_temp = os.path.join("files", "cache", "secondblob_lan.bin.temp")
    lan_bin = os.path.join("files", "cache", "secondblob_lan.bin")
    if os.path.isfile(lan_temp):
        blob_dict = read_secondblob(lan_temp)
    elif os.path.isfile(lan_bin):
        blob_dict = read_secondblob(lan_bin)
    else:
        blob_dict = read_secondblob("files/secondblob.bin")

    # read_secondblob now returns blob_dict directly (no "blob" wrapper)
    blob_ver = blob_dict[b"\x00\x00\x00\x00"]

    apps_to_neuter = {}
    apps_to_neuter_sorted = {}
    neuter_id = 1
    neuter_id_sorted = 1

    timestamp = globalvars.formatted_underscore_date + " " + config['steam_time']
    print(timestamp)

    if config["disable_storage_neutering"].lower() != "true":
        if timestamp > "2003-09-09 18_50_45":
        #if struct.unpack('H', blob_ver)[0] > 2:
            try:
                applist = get_app_list(blob_dict)
                log.info(f"Retrieved application list with {len(applist)} entries.")
                #applist = contentblob.get_app_list(cblob)
            except:
                log.error(f"Failed to get applist from Content Directory Server!")
                sys.exit()

            log.debug("Waiting for content server...")

            while is_port_in_use(config["server_ip"], int(config["content_server_port"])) == False:
                pass

            if not param2 == "app":
                if type(app_id) == int and len(version_list) > 0:
                    print("Entering standalone mode")
                    print(datetime.now())
                    
                    for app_ver in version_list:
                        if app_id in applist:
                            name = applist[app_id].name
                            #download_app(app_id, app_ver, name)
                            apps_to_neuter[neuter_id] = [app_id, app_ver, name, contentserver]
                            neuter_id += 1
                        else:
                            #download_app(app_id, app_ver, b"Unknown app")
                            apps_to_neuter[neuter_id] = [app_id, app_ver, b"Unknown app", contentserver]
                            neuter_id += 1
                    create_tkinter_window(apps_to_neuter) if _GUI_AVAILABLE else create_console_window(apps_to_neuter)
                    print(datetime.now())
                    sys.exit("Complete.")

            if not param3 == ",8":
                sys.exit("This program cannot be run in DOS mode.")

            subscribelist = []

            # Regex pattern to match storage_<appid>.json filenames (for custom neutering)
            pattern = re.compile(r"^storage_(\d+)\.json$")

            # Read filenames from the directory
            if os.path.isdir(custom_neuter_path):
                for filename in os.listdir(custom_neuter_path):
                    match = pattern.match(filename)
                    if match:
                        app_id = int(match.group(1))
                        if app_id not in neuter_applist:
                            neuter_applist.append(app_id)

            # Sort the list
            neuter_applist.sort()

            for app_id in neuter_applist:
                if app_id in applist:
                    appid = app_id
                    version = applist[appid].version
                    betaversion = applist[appid].betaversion
                    name = applist[appid].name
                    #log.info(f"Downloading and processing app {appid}: {name.decode('UTF-8')}, version {version}.")
                    #globalvars.CURRENT_APPID_VERSION = f"appid: {str(appid)} version: {str(version)}: "
                    #download_app(appid, version, name)
                    cache_subdir = os.path.join("files", "cache", f"{appid}_{version}")
                    if not os.path.isdir(cache_subdir):
                        apps_to_neuter[neuter_id] = [appid, version, name, contentserver]
                        neuter_id += 1
                    if betaversion != version:
                        #download_app(appid, betaversion, name)
                        beta_cache = os.path.join("files", "cache", f"{appid}_{betaversion}")
                        if not os.path.isdir(beta_cache):
                            apps_to_neuter[neuter_id] = [appid, betaversion, name, contentserver]
                            neuter_id += 1

            for app_id in ceg_applist:
                if app_id in applist:
                    appid = app_id
                    version = applist[appid].version
                    betaversion = applist[appid].betaversion
                    name = applist[appid].name
                    if Path("files", "drm", "ceg", f"{appid}_{version}").is_dir():
                        #log.info(f"Downloading and processing app {appid}: {name.decode('UTF-8')}, version {version}.")
                        #globalvars.CURRENT_APPID_VERSION = f"appid: {str(appid)} version: {str(version)}: "
                        #download_app(appid, version, name)
                        cache_subdir = os.path.join("files", "cache", f"{appid}_{version}")
                        if not os.path.isdir(cache_subdir):
                            apps_to_neuter[neuter_id] = [appid, version, name, contentserver]
                            neuter_id += 1
                    if (betaversion != version) and Path("files", "drm", "ceg", f"{appid}_{betaversion}").is_dir():
                        #download_app(appid, betaversion, name)
                        beta_cache = os.path.join("files", "cache", f"{appid}_{betaversion}")
                        if not os.path.isdir(beta_cache):
                            apps_to_neuter[neuter_id] = [appid, betaversion, name, contentserver]
                            neuter_id += 1

            res = {key: val for key, val in sorted(apps_to_neuter.items(), key = lambda ele: ele[1])}

            for item in res:
                apps_to_neuter_sorted[neuter_id_sorted] = res[item]
                neuter_id_sorted += 1

            if len(apps_to_neuter_sorted) > 0:
                create_tkinter_window(apps_to_neuter_sorted) if _GUI_AVAILABLE else create_console_window(apps_to_neuter_sorted)
            else:
                log.debug("Nothing to do")

    # Use the centralized safe rename function from utils
    from utils import rename_temp_blobs
    rename_temp_blobs()

    # Handle firstblob source file copy if needed (legacy behavior)
    cache_dir = os.path.join("files", "cache")
    firstblob = os.path.join(cache_dir, "firstblob.bin")
    source_firstblob = os.path.join("files", "firstblob.bin")

    if not os.path.isfile(firstblob) and os.path.isfile(source_firstblob):
        try:
            shutil.copy2(source_firstblob, firstblob)
            log.info("Copied source firstblob.bin to cache.")
        except Exception as e:
            log.warning(f"Failed to copy source firstblob.bin: {e}")

    neuter_steamworks_sdk()

    log_blob_information()

    # Rotate test log after blob change completes (if test logging is enabled)
    rotate_test_logging()


