def neuter_single_storage(appid: int, version: int) -> bool:
    """
    Neuter a single storage (appid, version) from the content server.

    This function is called by the custom_neuter_tracker when a storage
    config file has changed and the cache needs to be rebuilt.

    Args:
        appid: The application ID to neuter
        version: The version number to neuter

    Returns:
        True if neutering was successful or already done, False on error
    """
    log.info(f"Single storage neuter requested for appid={appid} version={version}")

    # Check if already cached
    cache_dir = os.path.join("files", "cache", f"{appid}_{version}")
    if os.path.isdir(cache_dir):
        log.info(f"Storage {appid}_{version} is already cached, skipping neuter")
        return True

    # Set up content server connection (same logic as auto_neuter)
    try:
        if config['csds_ipport'] == "":
            contentserver = (bytes(config["server_ip"], "UTF-8"), int(config["contentdir_server_port"]))
        else:
            csds_ipport = config['csds_ipport']
            ip, port = csds_ipport.split(':')
            port = int(port)
            contentserver = (ip, port)
    except Exception as e:
        log.warning(f"Error reading content server config: {e}. Using default localhost server.")
        contentserver = (b"127.0.0.1", 27037)

    # Load blob to get app info
    lan_temp = os.path.join("files", "cache", "secondblob_lan.bin.temp")
    lan_bin = os.path.join("files", "cache", "secondblob_lan.bin")
    if os.path.isfile(lan_temp):
        blob_dict = read_secondblob(lan_temp)
    elif os.path.isfile(lan_bin):
        blob_dict = read_secondblob(lan_bin)
    else:
        blob_dict = read_secondblob("files/secondblob.bin")

    try:
        # read_secondblob now returns blob_dict directly (no "blob" wrapper)
        applist = get_app_list(blob_dict)
    except Exception as e:
        log.error(f"Failed to get applist from blob: {e}")
        return False

    # Get app name
    if appid in applist:
        name = applist[appid].name
    else:
        name = b"Unknown app"

    # Create single-entry apps_to_neuter dict
    apps_to_neuter = {
        1: [appid, version, name, contentserver]
    }

    log.info(f"Starting single storage neuter for {name.decode('UTF-8', errors='ignore')} ({appid} v{version})")

    # Use the GUI to process (same as auto_neuter)
    try:
        create_tkinter_window(apps_to_neuter) if _GUI_AVAILABLE else create_console_window(apps_to_neuter)
        log.info(f"Single storage neuter completed for {appid}_{version}")
        return True
    except Exception as e:
        log.error(f"Failed to neuter single storage {appid}_{version}: {e}")
        return False
